//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packagewafimport("testing")funcTestValidMetricName(t*testing.T){t.Parallel()validNames:=[]string{"testrule","testRule","testRule123",}for_,v:=rangevalidNames{_,errors:=validMetricName(v,"name")iflen(errors)!=0{t.Fatalf("%qshouldbeavalidWAFmetricname:%q",v,errors)}}invalidNames:=[]string{"!","/","",":",";","whitespace","/slash-at-the-beginning","slash-at-the-end/",}for_,v:=rangeinvalidNames{_,errors:=validMetricName(v,"name")iflen(errors)==0{t.Fatalf("%qshouldbeaninvalidWAFmetricname",v)}}}